158→// ── Main ──────────────────────────────────────────────────────────
159→export default function Home() {
160→  const [messages, setMessages] = useState<Msg[]>([]);
161→  const [animatingIdx, setAnimatingIdx] = useState<number>(-1);
162→  const [input, setInput] = useState("");
163→  const [error, setError] = useState<string | null>(null);
164→  const [canvasState, setCanvasState] = useState<CanvasState>("idle");
165→  const [latestOmega, setLatestOmega] = useState("");
166→  const [showPill, setShowPill] = useState(false);
167→  const [statusText, setStatusText] = useState<string | null>(null);
168→  const textareaRef = useRef<HTMLTextAreaElement>(null);
169→  const feedRef = useRef<HTMLDivElement>(null);
170→  const [sessionId, setSessionId] = useState<string | null>(null);
171→  const [historyOpen, setHistoryOpen] = useState(false);
172→  const [sessionList, setSessionList] = useState<{id: string; created_at: string; preview: string}[]>([]);
173→
174→  const bottomRef = useRef<HTMLDivElement>(null);
175→  const inChatMode = messages.length > 0;
176→
177→  useEffect(() => {
178→    const handleKeyDown = (e: KeyboardEvent) => {
179→      if (e.key === "Escape") setHistoryOpen(false);
180→    };
181→    window.addEventListener("keydown", handleKeyDown);
182→    return () => window.removeEventListener("keydown", handleKeyDown);
183→  }, []);
184→
185→  useEffect(() => {
186→    if (historyOpen) {
187→      fetch('/api/sessions').then(res => res.json()).then(data => {
188→        if (Array.isArray(data)) setSessionList(data);
189→      }).catch(console.error);
190→    }
191→  }, [historyOpen]);
192→
193→  const loadSession = async (id: string) => {
194→    try {
195→      const res = await fetch(`/api/sessions/${id}`);
196→      const data = await res.json();
197→      if (Array.isArray(data)) {
198→        // eslint-disable-next-line @typescript-eslint/no-explicit-any
199→        setMessages(data.map((m: any) => ({ role: m.role, text: m.content, timestamp: m.created_at })));
200→        setSessionId(id);
201→        localStorage.setItem("omega_session", id);
202→        setHistoryOpen(false);
203→      }
204→    } catch (err) {
205→      console.error(err);
206→    }
207→  };
208→
209→  const startNewSession = () => {
210→    setMessages([]);
211→    setAnimatingIdx(-1);
212→    setLatestOmega("");
213→    setSessionId(null);
214→    localStorage.removeItem("omega_session");
215→    setHistoryOpen(false);
216→  };
217→  
218→  const newChat = startNewSession;
219→
220→
221→  // Auto-resize
222→  const autoResize = () => {
223→    if (!textareaRef.current) return;
224→    textareaRef.current.style.height = "auto";
225→    textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 200)}px`;
226→  };
227→
228→  useEffect(() => {
229→    const saved = localStorage.getItem("omega_session");
230→    // eslint-disable-next-line react-hooks/set-state-in-effect
231→    if (saved) setSessionId(saved);
232→  }, []);
233→  // Suppress unused-var lint — latestOmega is retained for future streaming use
234→  void latestOmega;
235→
236→  const scrollToBottom = () => {
237→    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
238→    setShowPill(false);
239→  };
240→
241→  const handleScroll = () => {
242→    const el = feedRef.current;
243→    if (!el) return;
244→    const isBottom = el.scrollHeight - el.scrollTop - el.clientHeight < 50;
245→    setShowPill(!isBottom);
246→  };
247→
248→  useEffect(() => {
249→    if (!showPill) {
250→      bottomRef.current?.scrollIntoView({ behavior: "smooth" });
251→    }
252→  }, [messages, canvasState, showPill]);
253→
254→  const send = useCallback(async (e?: React.FormEvent) => {
255→    e?.preventDefault();
256→    const text = input.trim();
257→    if (!text || canvasState === "thinking") return;
258→
259→    setInput("");
260→    setError(null);
261→    const newMessage: Msg = { role: "user", text, timestamp: new Date().toISOString() };
262→    const currentMessages = [...messages];
263→    setMessages(prev => [...prev, newMessage]);
264→    setCanvasState("thinking");
265→    setLatestOmega("");
266→    setShowPill(false);
267→
268→    try {
269→      const res = await chatStream(
270→        { user: text, history: currentMessages, sessionId: sessionId ?? undefined }, 
271→        (chunk) => {
272→          setStatusText(null); // First token arrives, clear status
273→          setMessages(prev => {
274→            const newMsgs = [...prev];
275→            const last = newMsgs[newMsgs.length - 1];
276→            if (last.role === "user") {
277→              newMsgs.push({ role: "omega", text: chunk, timestamp: new Date().toISOString() });
278→              setAnimatingIdx(newMsgs.length - 1);
279→              setCanvasState("idle");
280→            } else {
281→              newMsgs[newMsgs.length - 1] = { ...last, text: last.text + chunk };
282→            }
283→            return newMsgs;
284→          });
285→        },
286→        (status) => {
287→          setStatusText(status);
288→        }
289→      );
290→      
291→      if (res.sessionId && !sessionId) {
292→        setSessionId(res.sessionId);
293→        localStorage.setItem("omega_session", res.sessionId);
294→      }
295→
296→      setAnimatingIdx(-1);
297→      setStatusText(null); // End of stream
298→    } catch (err) {
299→      setError(err instanceof Error ? err.message : String(err));
300→      setCanvasState("idle");
301→      setStatusText(null);
302→    }
303→  }, [input, canvasState, messages, sessionId]);
304→
305→  const handleKey = (e: React.KeyboardEvent) => {
306→    if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); send(); }
307→  };
308→
309→  // ── Render ───────────────────────────────────────────────────────
310→  return (
311→    <>
312→      <OmegaCanvas state={canvasState} />
313→
314→      <div className={s.root}>
315→        {!inChatMode ? (
316→          /* ── LANDING ── */
317→          <>
318→            <div className={s.landing}>
319→              <div className={s.vignettePulse} />
320→              
321→              <div className={s.heroSection}>
322→                {canvasState === "thinking" && (
323→                  <div className={s.ringWrap}>
324→                    <div className={s.ring} />
325→                    <div className={s.ring} />
326→                    <div className={s.ring} />
327→                  </div>
328→                )}
329→                <div className={`${s.landingOmega} ${canvasState === "thinking" ? s.thinking : canvasState === "responding" ? s.responding : ""}`}>
330→                  Ω
331→                </div>
332→                <div className={s.taglineStack}>
333→                  <div className={s.tagline1}>Ω OmegA</div>
334→                  <div className={s.tagline2}>Sovereign Intelligence</div>
335→                  <div className={s.tagline3}>Engineered by Ryan Wayne Yett</div>
336→                </div>
337→              </div>
338→
339→              <div className={s.featureStrip}>
340→                <div className={s.featureCard}>
341→                  <div className={s.featureIcon}>M</div>
342→                  <div className={s.featureTitle}>Persistent Memory</div>
343→                  <div className={s.featureDesc}>MYELIN layer</div>
344→                </div>
345→                <div className={s.featureCard}>
346→                  <div className={s.featureIcon}>A</div>
347→                  <div className={s.featureTitle}>Identity-Anchored</div>
348→                  <div className={s.featureDesc}>AEON / CAR principle</div>
349→                </div>
350→                <div className={s.featureCard}>
351→                  <div className={s.featureIcon}>G</div>
352→                  <div className={s.featureTitle}>Governed Reasoning</div>
353→                  <div className={s.featureDesc}>AEGIS layer</div>
354→                </div>
355→              </div>
356→
357→              {canvasState === "thinking" && (
358→                <div className={s.landingThinkingContainer}>
359→                  <div className={s.thinkingDots}>
360→                    <span /><span /><span />
361→                  </div>
362→                </div>
363→              )}
364→
365→              <div className={s.landingInputWrap}>
366→                <div className={s.inputEyebrow}>Ask OmegA anything</div>
367→                <div className={s.inputContainerMaxWidth}>
368→                  <form onSubmit={send}>
369→                    <div className={s.inputBar}>
370→                      <textarea
371→                        ref={textareaRef}
372→                        className={s.textarea}
373→                        value={input}
374→                        onChange={e => { setInput(e.target.value); autoResize(); }}
375→                        onKeyDown={handleKey}
376→                        placeholder="Ask OmegA anything…"
377→                        rows={1}
378→                        disabled={canvasState === "thinking"}
379→                        autoFocus
380→                      />
381→                      <button
382→                        className={s.sendBtn}
383→                        type="submit"
384→                        disabled={!input.trim() || canvasState === "thinking"}
385→                        aria-label="Send message"
386→                      >
387→                        Ω
388→                      </button>
389→                    </div>
390→                  </form>
391→                </div>
392→                <div className={s.inputHint}>&crarr; to send</div>
393→              </div>
394→
395→              <div className={s.scrollHint}>
396→                <span className={s.chevron}></span>
397→                <span className={s.chevron}></span>
398→                <span className={s.chevron}></span>
399→              </div>
400→              
401→              <footer className={s.landingFooter}>
402→                <a href="/about" className={s.footerLink}>ABOUT OMEGA</a>
403→              </footer>
404→            </div>
405→          </>
406→        ) : (
407→          /* ── CHAT ── */
408→          <>
409→            <header className={`${s.header} ${canvasState === "thinking" ? s.headerThinking : ""}`}>
410→              <div className={s.headerInner}>
411→                <span className={`${s.headerOmega} ${canvasState === "thinking" ? s.thinking : ""}`}>Ω</span>
412→                <span className={s.headerName}>OmegA</span>
413→                <div className={s.headerGroup}>
414→                  <button className={s.historyBtn} title="View Session History" onClick={() => setHistoryOpen(true)}>
415→                    ⌘ History
416→                  </button>
417→                  <div className={s.statusDot} />
418→                  Sovereign
419→                </div>
420→                <div className={s.headerSession}>Session active</div>
421→                <button
422→                  className={s.newChatBtn}
423→                  onClick={newChat}
424→                  title="New chat"
425→                  aria-label="Start new chat"
426→                >
427→                  + New
428→                </button>
429→              </div>
430→              <div className={s.headerGradientLine} />
431→            </header>
432→
433→            <div
434→              className={s.feed}
435→              role="log"
436→              aria-live="polite"
437→              aria-label="Chat messages"
438→              ref={feedRef}
439→              onScroll={handleScroll}
440→            >
441→              {messages.map((msg, i) =>
442→                msg.role === "user" ? (
443→                  <div key={i} className={s.msgUserWrap}>
444→                    <div className={s.msgUser}>{msg.text}</div>
445→                    {msg.timestamp && <div className={s.msgTimestampUser}>{new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</div>}
446→                  </div>
447→                ) : (
448→                  <OmegaMsg key={i} text={msg.text} animate={i === animatingIdx} timestamp={msg.timestamp} />
449→                )
450→              )}
451→
452→              {canvasState === "thinking" && <ThinkingIndicator status={statusText} />}
453→
454→              {error && <div className={s.error} role="alert">⚠ {error}</div>}
455→              <div ref={bottomRef} style={{ height: 1 }} />
456→            </div>
457→
458→            {showPill && (
459→              <div className={s.scrollPillWrap}>
460→                <button className={s.scrollPill} onClick={scrollToBottom} aria-label="Scroll to bottom">
461→                  ↓ New response
462→                </button>
463→              </div>
464→            )}
465→
466→            <div className={s.inputWrap}>
467→              <form onSubmit={send}>
468→                <div className={`${s.inputBar} ${input.trim() ? s.hasInput : ''}`}>
469→                  <button type="button" className={s.attachBtn} aria-label="Attach file" disabled={canvasState === "thinking"}>
470→                    <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{opacity: 0.6}}><path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48"/></svg>
471→                  </button>
472→                  <textarea
473→                    ref={textareaRef}
474→                    className={s.textarea}
475→                    value={input}
476→                    onChange={e => { setInput(e.target.value); autoResize(); }}
477→                    onKeyDown={handleKey}
478→                    placeholder="Ask OmegA anything…"
479→                    rows={1}
480→                    disabled={canvasState === "thinking"}
481→                    autoFocus
482→                  />
483→                  {input.length > 200 && (
484→                    <div className={s.charCount}>{input.length}</div>
485→                  )}
486→                  <button
487→                    className={`${s.sendBtn} ${input.trim() ? s.pulse : ''}`}
488→                    type="submit"
489→                    disabled={!input.trim() || canvasState === "thinking"}
490→                    aria-label="Send message"
491→                  >
492→                    Ω
493→                  </button>
494→                </div>
495→              </form>
496→            </div>
497→          </>
498→        )}
499→      </div>
500→
501→      {/* History Panel */}
502→      {historyOpen && <div className={s.historyOverlay} onClick={() => setHistoryOpen(false)} />}
503→      <div className={`${s.historyPanel} ${historyOpen ? s.open : ""}`}>
504→        <div className={s.historyPanelHeader}>
505→          <span>Session History</span>
506→          <button onClick={startNewSession}>+ New</button>
507→        </div>
508→        <div className={s.historyList}>
509→          {sessionList.map(session => (
510→            <div key={session.id} className={s.historyItem} onClick={() => loadSession(session.id)}>
511→              <span className={s.historyPreview}>
512→                {session.preview ? (session.preview.length > 60 ? session.preview.slice(0, 60) + "..." : session.preview) : "Empty Session"}
513→              </span>
514→              <span className={s.historyTime}>{formatRelativeTime(session.created_at)}</span>
515→            </div>
516→          ))}
517→        </div>
518→      </div>
519→    </>
520→  );
521→}
