  1→@import url('https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Space+Grotesk:wght@300;400;500;600&display=swap');
  2→
  3→:root {
  4→  --void: #02020c;
  5→  --indigo: #6366f1;
  6→  --violet: #8b5cf6;
  7→  --lavender: #c4b5fd;
  8→  --gold: #e4b84a;
  9→  --white: #f1f5f9;
 10→  --dim: rgba(241, 245, 249, 0.45);
 11→  --dimmer: rgba(241, 245, 249, 0.18);
 12→  --glass-bg: rgba(8, 8, 28, 0.72);
 13→  --glass-border: rgba(139, 92, 246, 0.18);
 14→  --space-1: 0.25rem;
 15→  --space-2: 0.5rem;
 16→  --space-3: 0.75rem;
 17→  --space-4: 1rem;
 18→  --space-5: 1.5rem;
 19→  --space-6: 2rem;
 20→  --space-7: 3rem;
 21→  --space-8: 4rem;
 22→  --ease-snappy: cubic-bezier(0.16, 1, 0.3, 1);
 23→  --ease-smooth: cubic-bezier(0.4, 0, 0.2, 1);
 24→}
 25→
 26→*:focus-visible {
 27→  outline: 2px solid rgba(139, 92, 246, 0.6);
 28→  outline-offset: 3px;
 29→}
 30→
 31→*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
 32→
 33→html, body {
 34→  height: 100%;
 35→  overflow: hidden;
 36→  background: var(--void);
 37→  color: var(--white);
 38→  font-family: 'Space Grotesk', system-ui, sans-serif;
 39→  -webkit-font-smoothing: antialiased;
 40→  overscroll-behavior: none;
 41→}
 42→
 43→/* Scrollbar */
 44→::-webkit-scrollbar { width: 3px; }
 45→::-webkit-scrollbar-track { background: transparent; }
 46→::-webkit-scrollbar-thumb { background: rgba(139, 92, 246, 0.3); border-radius: 2px; }
 47→
 48→/* ── Keyframes ───────────────────────────────────────────────────── */
 49→
 50→@keyframes omega-breathe {
 51→  0%, 100% { filter: drop-shadow(0 0 18px rgba(99,102,241,0.6)) drop-shadow(0 0 50px rgba(139,92,246,0.25)); }
 52→  50%       { filter: drop-shadow(0 0 30px rgba(139,92,246,0.9)) drop-shadow(0 0 80px rgba(99,102,241,0.35)); }
