input.content:
/* ── Landing Container ──────────────────────────────────────────── */
.landing {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
  padding-top: 12vh;
  gap: 0;
  padding-bottom: 100px;
  position: relative;
  overflow-y: auto;
  overflow-x: hidden;
}

/* ── Ambient Vignette ──────────────────────────────────────────── */
.vignette {
  position: fixed;
  inset: 0;
  pointer-events: none;
  background: radial-gradient(
    ellipse 60% 50% at 50% 40%,
    rgba(139, 92, 246, 0.1) 0%,
    rgba(99, 102, 241, 0.04) 40%,
    transparent 70%
  );
  animation: vignette-breathe 6s ease-in-out infinite;
  z-index: 0;
}

@keyframes vignette-breathe {
  0%, 100% { opacity: 0.4; }
  50% { opacity: 1; }
}

/* ── Hero Section ──────────────────────────────────────────────── */
.hero {
  display: flex;
  flex-direction: column;
  align-items: center;
  position: relative;
  z-index: 1;
  margin-bottom: var(--space-7);
}

/* ── Ring Pulse (thinking state) ───────────────────────────────── */
.ringWrap {
  position: absolute;
  inset: 0;
  display: flex;
  align-items: center;
  justify-content: center;
  pointer-events: none;
}

.ring {
  position: absolute;
  width: 180px;
  height: 180px;
  border-radius: 50%;
  border: 1px solid rgba(228, 184, 74, 0.25);
  animation: ring-pulse 2s ease-out infinite;
}

.ring:nth-child(2) { animation-delay: 0.6s; }
.ring:nth-child(3) { animation-delay: 1.2s; }

@keyframes ring-pulse {
  0%   { transform: scale(1); opacity: 0.6; }
  100% { transform: scale(2.5); opacity: 0; }
}

/* ── Omega Glyph ───────────────────────────────────────────────── */
.omega {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(110px, 24vw, 200px);
  font-weight: 900;
  color: var(--gold);
  line-height: 1;
  user-select: none;
  animation: omega-breathe 4s ease-in-out infinite;
  transition: all 0.6s var(--ease-snappy);
  letter-spacing: -0.02em;
  will-change: filter, transform;
  cursor: default;
}

.omega.thinking {
  animation: omega-think 1.1s ease-in-out infinite;
}

.omega.responding {
  animation: omega-respond 1.5s ease-out forwards;
}

/* ── Title + Subtitle ──────────────────────────────────────────── */
.titleStack {
  display: flex;
  flex-direction: column;
  align-items: center;
  margin-top: var(--space-4);
  text-align: center;
}

.title {
  font-family: 'Orbitron', sans-serif;
  font-size: clamp(20px, 4vw, 28px);
  font-weight: 700;
  color: var(--gold);
  letter-spacing: 0.35em;
  text-transform: uppercase;
  opacity: 0;
  animation: fade-up 0.8s var(--ease-smooth) forwards;
  animation-delay: 0.2s;
  margin-bottom: var(--space-3);
}

.subtitle {
  font-family: 'Space Grotesk', system-ui, sans-serif;
  font-size: clamp(14px, 3vw, 17px);
  color: var(--lavender);
  letter-spacing: 0.22em;
  opacity: 0;
  animation: fade-up 0.8s var(--ease-smooth) forwards;
  animation-delay: 0.45s;
  margin-bottom: var(--space-1);
}

.byline {
  font-family: 'Space Grotesk', system-ui, sans-serif;
  font-size: clamp(11px, 2.5vw, 13px);
  color: var(--dimmer);
  font-style: italic;
  letter-spacing: 0.05em;
  opacity: 0;
  animation: fade-up 0.8s var(--ease-smooth) forwards;
  animation-delay: 0.65s;
}

/* ── Feature Cards ─────────────────────────────────────────────── */
.featureStrip {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: var(--space-4);
  width: 100%;
  max-width: 960px;
  padding: 0 var(--space-5);
  z-index: 1;
  margin-bottom: var(--space-7);
}

.card {
  background: rgba(8, 8, 28, 0.55);
  border: 1px solid rgba(139, 92, 246, 0.12);
  border-radius: 16px;
  padding: var(--space-5) var(--space-4);
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  backdrop-filter: blur(16px);
  -webkit-backdrop-filter: blur(16px);
  opacity: 0;
  animation: card-enter 0.9s var(--ease-smooth) forwards;
  transition:
    transform 0.35s var(--ease-snappy),
    box-shadow 0.35s var(--ease-snappy),
    border-color 0.35s var(--ease-snappy);
  position: relative;
  overflow: hidden;
}

/* Glass sheen */
.card::before {
  content: '';
  position: absolute;
  top: 0;
  left: -75%;
  width: 50%;
  height: 100%;
  background: linear-gradient(
    90deg,
    transparent,
    rgba(196, 181, 253, 0.04),
    transparent
  );
  transform: skewX(-15deg);
  transition: left 0.6s ease;
  pointer-events: none;
}

.card:hover::before {
  left: 125%;
}

/* Staggered entrance */
.card:nth-child(1) { animation-delay: 0.6s; }
.card:nth-child(2) { animation-delay: 0.75s; }
.card:nth-child(3) { animation-delay: 0.9s; }
.card:nth-child(4) { animation-delay: 1.05s; }

@keyframes card-enter {
  from {
    opacity: 0;
    transform: translateY(24px) scale(0.96);
  }
  to {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.card:hover {
  transform: translateY(-6px);
  box-shadow:
    0 12px 40px rgba(139, 92, 246, 0.18),
    0 0 1px rgba(196, 181, 253, 0.3);
  border-color: rgba(139, 92, 246, 0.4);
}

.cardIcon {
  font-family: 'Orbitron', sans-serif;
  font-size: 28px;
  color: var(--lavender);
  margin-bottom: var(--space-3);
  font-weight: 700;
  text-shadow: 0 0 16px rgba(196, 181, 253, 0.5);
  transition: text-shadow 0.3s ease, transform 0.3s ease;
  line-height: 1;
}

.card:hover .cardIcon {
  text-shadow: 0 0 28px rgba(196, 181, 253, 0.9);
  transform: scale(1.1);
}

.cardTitle {
  font-family: 'Space Grotesk', system-ui, sans-serif;
  font-size: 15px;
  font-weight: 600;
  color: var(--white);
  margin-bottom: var(--space-2);
  letter-spacing: 0.02em;
}

.cardDesc {
  font-family: 'Space Grotesk', system-ui, sans-serif;
  font-size: 12.5px;
  color: var(--dim);
  line-height: 1.5;
}

/* ── Input Area ────────────────────────────────────────────────── */
.inputSection {
  display: flex;
  flex-direction: column;
  align-items: center;
  width: 100%;
  z-index: 2;
  padding: 0 var(--space-5);
  opacity: 0;
  animation: fade-up 0.8s var(--ease-smooth) forwards;
  animation-delay: 1.2s;
}

.inputLabel {
  font-family: 'Space Grotesk', system-ui, sans-serif;
  font-size: 13px;
  color: var(--dim);
  margin-bottom: var(--space-3);
  letter-spacing: 0.06em;
}

.inputWrap {
  max-width: 640px;
  width: 100%;
}

.inputBar {
  display: flex;
  align-items: center;
  background: rgba(8, 8, 28, 0.65);
  border: 1px solid rgba(139, 92, 246, 0.2);
  border-radius: 14px;
  padding: var(--space-2) var(--space-3);
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  transition: border-color 0.3s ease, box-shadow 0.3s ease;
}

.inputBar:focus-within {
  border-color: rgba(139, 92, 246, 0.5);
  box-shadow: 0 0 20px rgba(139, 92, 246, 0.1);
}

.textarea {
  flex: 1;
  background: transparent;
  border: none;
  outline: none;
  color: var(--white);
  font-family: 'Space Grotesk', system-ui, sans-serif;
  font-size: 15px;
  line-height: 1.5;
  resize: none;
  padding: var(--space-2) var(--space-2);
  max-height: 180px;
}

.textarea::placeholder {
  color: var(--dimmer);
  font-style: italic;
}

.sendBtn {
  background: linear-gradient(135deg, var(--indigo), var(--violet));
  border: none;
  color: var(--white);
  font-family: 'Orbitron', sans-serif;
  font-size: 18px;
  font-weight: 700;
  width: 44px;
  height: 44px;
  border-radius: 12px;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: transform 0.2s ease, box-shadow 0.2s ease, opacity 0.2s ease;
  flex-shrink: 0;
  opacity: 0.45;
}

.sendBtn:not(:disabled) {
  opacity: 1;
}

.sendBtn:not(:disabled):hover {
  transform: scale(1.06);
  box-shadow: 0 0 20px rgba(99, 102, 241, 0.4);
}

.sendBtn:disabled {
  cursor: not-allowed;
}

.inputHint {
  font-size: 11px;
  color: var(--dimmer);
  margin-top: var(--space-2);
  text-align: center;
  letter-spacing: 0.04em;
}

/* ── Thinking state on landing ─────────────────────────────────── */
.thinkingDots {
  display: flex;
  gap: 6px;
  justify-content: center;
  margin-top: var(--space-4);
}

.thinkingDots span {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--gold);
  animation: dot-bounce 1.4s ease-in-out infinite;
}

.thinkingDots span:nth-child(2) { animation-delay: 0.16s; }
.thinkingDots span:nth-child(3) { animation-delay: 0.32s; }

@keyframes dot-bounce {
  0%, 80%, 100% { transform: translateY(0); opacity: 0.3; }
  40%            { transform: translateY(-6px); opacity: 1; }
}

/* ── Footer ────────────────────────────────────────────────────── */
.footer {
  margin-top: auto;
  padding-top: var(--space-7);
  text-align: center;
}

.footerLink {
  font-family: 'Space Grotesk', system-ui, sans-serif;
  font-size: 11px;
  color: var(--dimmer);
  text-decoration: none;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  transition: color 0.3s ease;
}

.footerLink:hover {
  color: var(--lavender);
}

/* ── Responsive ────────────────────────────────────────────────── */
@media (max-width: 768px) {
  .featureStrip {
    grid-template-columns: repeat(2, 1fr);
    gap: var(--space-3);
    padding: 0 var(--space-3);
  }

  .landing {
    padding-top: 8vh;
  }
}

@media (max-width: 420px) {
  .featureStrip {
    grid-template-columns: 1fr;
    max-width: 320px;
  }
}

"use client";

import { useState, useRef, useCallback } from "react";
import s from "./Landing.module.css";

interface LandingProps {
  onFirstMessage: (text: string) => void;
  isThinking?: boolean;
}

const FEATURES = [
  {
    icon: "\u039C",
    title: "Persistent Memory",
    desc: "MYELIN graph memory hardens retrieval paths with use — nothing is forgotten.",
  },
  {
    icon: "\u03A6",
    title: "Identity Anchoring",
    desc: "AEON Phylactery chain ensures cryptographic continuity of self across sessions.",
  },
  {
    icon: "\u03A3",
    title: "Synthesis Engine",
    desc: "ADCCL cognitive control loop with claim budgets and anti-drift self-tagging.",
  },
  {
    icon: "\u0391",
    title: "Governed Reasoning",
    desc: "AEGIS policy shell enforces model-agnostic governance at the API boundary.",
  },
];

export default function Landing({ onFirstMessage, isThinking = false }: LandingProps) {
  const [input, setInput] = useState("");
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const autoResize = () => {
    if (!textareaRef.current) return;
    textareaRef.current.style.height = "auto";
    textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 180)}px`;
  };

  const handleSubmit = useCallback(
    (e?: React.FormEvent) => {
      e?.preventDefault();
      const text = input.trim();
      if (!text || isThinking) return;
      setInput("");
      onFirstMessage(text);
    },
    [input, isThinking, onFirstMessage],
  );

  const handleKey = (e: React.KeyboardEvent) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  return (
    <div className={s.landing}>
      <div className={s.vignette} />

      {/* Hero */}
      <div className={s.hero}>
        {isThinking && (
          <div className={s.ringWrap}>
            <div className={s.ring} />
            <div className={s.ring} />
            <div className={s.ring} />
          </div>
        )}

        <div
          className={`${s.omega} ${isThinking ? s.thinking : ""}`}
        >
          {"\u03A9"}
        </div>

        <div className={s.titleStack}>
          <div className={s.title}>OmegA</div>
          <div className={s.subtitle}>Sovereign. Persistent. Self-Knowing.</div>
          <div className={s.byline}>Engineered by Ryan Wayne Yett</div>
        </div>
      </div>

      {/* Feature Cards */}
      <div className={s.featureStrip}>
        {FEATURES.map((f) => (
          <div key={f.title} className={s.card}>
            <div className={s.cardIcon}>{f.icon}</div>
            <div className={s.cardTitle}>{f.title}</div>
            <div className={s.cardDesc}>{f.desc}</div>
          </div>
        ))}
      </div>

      {/* Thinking indicator */}
      {isThinking && (
        <div className={s.thinkingDots}>
          <span />
          <span />
          <span />
        </div>
      )}

      {/* Input */}
      <div className={s.inputSection}>
        <div className={s.inputLabel}>Begin a conversation</div>
        <div className={s.inputWrap}>
          <form onSubmit={handleSubmit}>
            <div className={s.inputBar}>
              <textarea
                ref={textareaRef}
                className={s.textarea}
                value={input}
                onChange={(e) => {
                  setInput(e.target.value);
                  autoResize();
                }}
                onKeyDown={handleKey}
                placeholder="Begin a conversation..."
                rows={1}
                disabled={isThinking}
                autoFocus
              />
              <button
                className={s.sendBtn}
                type="submit"
                disabled={!input.trim() || isThinking}
                aria-label="Send message"
              >
                {"\u03A9"}
              </button>
            </div>
          </form>
          <div className={s.inputHint}>&crarr; to send</div>
        </div>
      </div>

      {/* Footer */}
      <footer className={s.footer}>
        <a href="/about" className={s.footerLink}>
          About OmegA
        </a>
      </footer>
    </div>
  );
}

"use client";

import { useEffect, useRef } from "react";

export type CanvasState = "idle" | "thinking" | "responding";

interface Particle {
  x: number; y: number;
  vx: number; vy: number;
  size: number;
  opacity: number;
  rgb: string;
  phase: number;
  phaseSpeed: number;
}

interface FieldLine {
  pts: number[];   // x0,y0, cx1,cy1, cx2,cy2, x1,y1
  vel: number[];   // dx for each control point
  opacity: number;
}

function hex(h: string): string {
  const r = parseInt(h.slice(1, 3), 16);
  const g = parseInt(h.slice(3, 5), 16);
  const b = parseInt(h.slice(5, 7), 16);
  return `${r},${g},${b}`;
}

const COLORS = ["#3b4fd8", "#6d4ff5", "#9b7cfa", "#c4b5fd", "#818cf8"].map(hex);

export default function OmegaCanvas({ state }: { state: CanvasState }) {
  const ref = useRef<HTMLCanvasElement>(null);
  const stateRef = useRef(state);
  useEffect(() => { stateRef.current = state; }, [state]);

  useEffect(() => {
    const canvas = ref.current;
    if (!canvas) return;
    const ctx = canvas.getContext("2d");
    if (!ctx) return;

    let raf: number;
    let W = 0, H = 0;
    let frame = 0;

    const resize = () => {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
    };
    window.addEventListener("resize", resize);
    resize();

    // Particles
    const COUNT = 140;
    const particles: Particle[] = Array.from({ length: COUNT }, () => ({
      x: Math.random() * W,
      y: Math.random() * H,
      vx: (Math.random() - 0.5) * 0.35,
      vy: (Math.random() - 0.5) * 0.35,
      size: Math.random() * 1.8 + 0.4,
      opacity: Math.random() * 0.55 + 0.1,
      rgb: COLORS[Math.floor(Math.random() * COLORS.length)],
      phase: Math.random() * Math.PI * 2,
      phaseSpeed: 0.008 + Math.random() * 0.018,
    }));

    // Field lines
    const LINES = 10;
    const lines: FieldLine[] = Array.from({ length: LINES }, () => ({
      pts: [
        Math.random() * W, Math.random() * H,
        Math.random() * W, Math.random() * H,
        Math.random() * W, Math.random() * H,
        Math.random() * W, Math.random() * H,
      ],
      vel: Array.from({ length: 8 }, () => (Math.random() - 0.5) * 0.25),
      opacity: Math.random() * 0.07 + 0.02,
    }));

    const draw = () => {
      raf = requestAnimationFrame(draw);
      frame++;

      const s = stateRef.current;
      const speed = s === "thinking" ? 2.8 : s === "responding" ? 1.6 : 1;
      const glow = s === "thinking" ? 0.18 + 0.12 * Math.sin(frame * 0.08) : s === "responding" ? 0.08 : 0;

      // Trailing clear
      ctx.fillStyle = "rgba(2, 2, 12, 0.18)";
      ctx.fillRect(0, 0, W, H);

      // Central pulse glow when thinking
      if (glow > 0) {
        const g = ctx.createRadialGradient(W / 2, H / 2, 0, W / 2, H / 2, Math.min(W, H) * 0.55);
        g.addColorStop(0, `rgba(99,60,220,${glow})`);
        g.addColorStop(0.5, `rgba(60,40,180,${glow * 0.4})`);
        g.addColorStop(1, "rgba(0,0,0,0)");
        ctx.fillStyle = g;
        ctx.fillRect(0, 0, W, H);
      }

      // Field lines
      for (const fl of lines) {
        for (let i = 0; i < fl.pts.length; i++) {
          fl.pts[i] += fl.vel[i] * speed;
          if (fl.pts[i] < -200 || fl.pts[i] > (i % 2 === 0 ? W : H) + 200) fl.vel[i] *= -1;
        }
        const [x0, y0, cx1, cy1, cx2, cy2, x1, y1] = fl.pts;
        const grad = ctx.createLinearGradient(x0, y0, x1, y1);
        const op = fl.opacity * (s === "thinking" ? 2.2 : s === "responding" ? 1.4 : 1);
        grad.addColorStop(0, `rgba(80,50,220,0)`);
        grad.addColorStop(0.5, `rgba(110,70,240,${op})`);
        grad.addColorStop(1, `rgba(80,50,220,0)`);
        ctx.beginPath();
        ctx.moveTo(x0, y0);
        ctx.bezierCurveTo(cx1, cy1, cx2, cy2, x1, y1);
        ctx.strokeStyle = grad;
        ctx.lineWidth = 1;
        ctx.stroke();
      }

      // Connections
      const maxDist = s === "thinking" ? 110 : 85;
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const d = Math.sqrt(dx * dx + dy * dy);
          if (d < maxDist) {
            const a = (1 - d / maxDist) * 0.12 * (s === "thinking" ? 2.5 : 1);
            ctx.beginPath();
            ctx.moveTo(particles[i].x, particles[i].y);
            ctx.lineTo(particles[j].x, particles[j].y);
            ctx.strokeStyle = `rgba(120,80,255,${a})`;
            ctx.lineWidth = 0.5;
            ctx.stroke();
          }
        }
      }

      // Particles
      for (const p of particles) {
        p.x += p.vx * speed;
        p.y += p.vy * speed;
        p.phase += p.phaseSpeed * speed;
        if (p.x < 0) p.x = W;
        if (p.x > W) p.x = 0;
        if (p.y < 0) p.y = H;
        if (p.y > H) p.y = 0;

        const pulse = 0.5 + 0.5 * Math.sin(p.phase);
        const op = p.opacity * pulse * (s === "thinking" ? 1.5 : 1);
        const sz = p.size * (0.7 + 0.3 * pulse);

        // Soft glow
        const grd = ctx.createRadialGradient(p.x, p.y, 0, p.x, p.y, sz * 5);
        grd.addColorStop(0, `rgba(${p.rgb},${op})`);
        grd.addColorStop(1, `rgba(${p.rgb},0)`);
        ctx.beginPath();
        ctx.arc(p.x, p.y, sz * 5, 0, Math.PI * 2);
        ctx.fillStyle = grd;
        ctx.fill();

        // Core
        ctx.beginPath();
        ctx.arc(p.x, p.y, sz, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${p.rgb},${Math.min(op * 2, 1)})`;
        ctx.fill();
      }

      // Arc sparks when thinking
      if (s === "thinking" && frame % 8 === 0) {
        const cx = W / 2 + (Math.random() - 0.5) * 60;
        const cy = H / 2 + (Math.random() - 0.5) * 60;
        ctx.beginPath();
        ctx.arc(cx, cy, Math.random() * 80 + 20, 0, Math.PI * 2 * Math.random());
        ctx.strokeStyle = `rgba(180,140,255,${Math.random() * 0.15})`;
        ctx.lineWidth = 0.5;
        ctx.stroke();
      }
    };

    draw();
    return () => {
      cancelAnimationFrame(raf);
      window.removeEventListener("resize", resize);
    };
  }, []);

  return (
    <canvas
      ref={ref}
      style={{
        position: "fixed", inset: 0,
        width: "100%", height: "100%",
        zIndex: 0, pointerEvents: "none",
        background: "#02020c",
        willChange: "transform",
      }}
    />
  );
}

